var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"부, 부사장님. 보고드립니다.","JPN":"ふ、副社長。ご報告いたします。","ENG":"V-vice President... I have some bad news to report.","TWN":"報…報告副總。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"조금 전 발생한 강력한 폭발과 함께…… 힐데 소대장님의 신호가 사라졌습니다.","JPN":"先ほど発生した強力な爆発とともに……ヒルデ小隊長の信号が途絶えました。","ENG":"Following the massive explosion just before, Commander Hilde's signal has vanished.","TWN":"剛才發生強烈爆炸後……就沒看到希爾德小隊長的信號。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……당했군요.","JPN":"……やられましたね。","ENG":"...They got us.","TWN":"……看來是凶多吉少。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 스승님이 나설 수밖에 없는 적을 준비해 놓은 것부터 수상했는데.","JPN":"だいたい師匠が出るしかない敵を準備しておいたことから怪しかったですが。","ENG":"It seemed suspicious that they had planned an enemy that only Master could handle.","TWN":"我剛就覺得奇怪，為什麼要派出非得逼師父出馬不可的對手。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어떻게 된 거지? 설마 힐데 소대장은 전사한 건가?","JPN":"どういうことだ？　まさかヒルデ小隊長は戦死したのか？","ENG":"What’s going on? Has Commander Hilde fallen?","TWN":"怎麼回事？希爾德小隊長該不會已經戰死沙場？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아뇨. 스승님이 그리 쉽게 죽을 리 없죠.","JPN":"いいえ。師匠がそう簡単に死ぬわけありません。","ENG":"No, Master isn’t one to fall so easily.","TWN":"不，師父沒那麼容易死掉的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아마 균열이 발생한 시점에 전투 중 방출된 에너지로 인해 다른 차원으로 전이되었을 겁니다.","JPN":"多分亀裂が発生した時点で、戦闘中に放出されたエネルギーによって違う次元へと転移させられたはずです。","ENG":"She appears to have been transported to another dimension by the energy released during the battle when the rift opened.","TWN":"應該是產生裂縫當下，由於戰鬥中釋放出的能量而掉到其他次元。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 즉시 복귀할 수 있다는 건가?","JPN":"それならただちに復帰できるということなのか？","ENG":"Does this mean she'll be able to return immediately?","TWN":"那她可以馬上回來嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다시 돌아오기까지는 시간이 꽤 걸리겠죠.","JPN":"戻ってくるまで結構時間がかかるでしょう。","ENG":"It’ll take some time for her to return to us.","TWN":"回來會需要花很長的時間。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우린 싸우기도 전에 가장 강력한 무기를 잃은 셈이군요.","JPN":"私たちは戦う前にもっとも強力な武器を失ったことになりますね。","ENG":"So we've effectively lost our trump card even before the battle begins.","TWN":"意思就是我們在開戰前夕，損失一枚最厲害的武器。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그거 곤란하군…….","JPN":"それはまいったな……","ENG":"That is bad news...","TWN":"糟糕……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"실례합니다, 중장님. 척후 임무 중 보고드릴 사안이 생겼어요.","JPN":"失礼いたします、中将。斥候の任務途中、ご報告する事案が発生しました。","ENG":"Excuse my interruption, Lieutenant General. During our recon, we discovered something important that you should be aware of.","TWN":"抱歉，中將，我正在執行偵察任務，有事情要向您報告。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저건…… 리플레이서 퀸의 재생체로군요.","JPN":"あれは……リプレイサー・クイーンの再生体ですね。","ENG":"That’s... the Regenerated Replacer Queen.","TWN":"那是……克隆·女皇的再生體？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"처분하지 않았던 건가요?","JPN":"処分していなかったのですか？","ENG":"You didn’t dispose of her?","TWN":"還沒有處理掉嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"인력난을 겪고 있는 건 우리나 그쪽이나 마찬가지 아닌가?","JPN":"人手不足なのはお互い様ではないか？","ENG":"You're not the only one having difficulty finding personnel.","TWN":"誰叫我們和你們一樣，都在鬧人才荒呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제이나는 사망한 리플레이서 퀸의 재생체야. 정상참작의 여지가 있지.","JPN":"ジェイナは死亡したリプレイサー・クイーンの再生体だ。情状酌量の余地がある。","ENG":"Jaina is the regenerated form of the deceased Replacer Queen. We determined that there are extenuating circumstances.","TWN":"婕娜是死去克隆·女皇的再生體，她的去留是有討論空間的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"도미닉과 그녀는 분명 잘못된 선택을 했어.","JPN":"ドミニクと彼女は確かに間違った選択をした。","ENG":"Without a doubt, she and Dominic made the wrong decision.","TWN":"多明尼克和她確實是做出錯誤的選擇，"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};